import sys
from functools import lru_cache

def main():
    input_data = sys.stdin.read().split()
    n = int(input_data[0])
    A = list(map(int, input_data[1:n+1]))

    # State: (l, r, last_idx) where last_idx = l-1 or r+1, or n meaning -inf
    # last_val = A[last_idx] if 0 <= last_idx < n else -1

    sys.setrecursionlimit(300000)

    @lru_cache(maxsize=None)
    def dp(l, r, last_idx):
        # last_idx: index into A for last value, or n for -inf (sentinel)
        if last_idx == n:
            last = -1
        else:
            last = A[last_idx]

        if l > r:
            return False

        can_l = A[l] > last
        can_r = A[r] > last

        if not can_l and not can_r:
            return False

        # Try left: next state last_idx = l (A[l] was taken, new left is l+1, so last = A[(l+1)-1] = A[l])
        if can_l:
            if not dp(l + 1, r, l):
                return True

        # Try right: next state last_idx = r (A[r] was taken, new right is r-1, so last = A[(r-1)+1] = A[r])
        if can_r:
            if not dp(l, r - 1, r):
                return True

        return False

    # Initial state: l=0, r=n-1, last=-inf encoded as n
    result = dp(0, n - 1, n)

    if result:
        print("Alice")
    else:
        print("Bob")

main()
